public class StringDefinition {
  public static void main(String[] args) {
    String text = "Salam, Dünya!";
    System.out.println("Sətir: " + text);
  }
}
// Çıxış: Sətir: Salam, Dünya!

public class StringImmutability {
  public static void main(String[] args) {
    String text = "Salam";
    text = text + ", Dünya!"; // Yeni sətir yaradılır
    System.out.println("Nəticə: " + text);
  }
}
// Çıxış: Nəticə: Salam, Dünya!

public class StringConcatenation {
  public static void main(String[] args) {
    String first = "Salam";
    String second = "Dünya";
    String result = first + ", " + second + "!";
    System.out.println("Birləşmiş sətir: " + result);
    // concat metodu ilə
    String concatResult = first.concat(" ").concat(second);
    System.out.println("Concat ilə: " + concatResult);
  }
}
// Çıxış:
// Birləşmiş sətir: Salam, Dünya!
// Concat ilə: Salam Dünya

public class StringMethods {
  public static void main(String[] args) {
    String text = "Java Öyrənmək";
    System.out.println("Uzunluq: " + text.length());
    System.out.println("Böyük hərflə: " + text.toUpperCase());
    System.out.println("Kiçik hərflə: " + text.toLowerCase());
    System.out.println("Alt sətir: " + text.substring(5, 10));
    System.out.println("5-ci simvol: " + text.charAt(5));
    System.out.println("Öyrənmək sözünün indeksi: " + text.indexOf("Öyrənmək"));
    System.out.println("Dəyişdirilmiş: " + text.replace("Öyrənmək", "Proqramlaşdırma"));
  }
}
// Çıxış:
// Uzunluq: 13
// Böyük hərflə: JAVA ÖYRƏNMƏK
// Kiçik hərflə: java öyrənmək
// Alt sətir: Öyrən
// 5-ci simvol: Ö
// Öyrənmək sözünün indeksi: 5
// Dəyişdirilmiş: Java Proqramlaşdırma

public class StringComparison {
  public static void main(String[] args) {
    String text1 = "Salam";
    String text2 = "salam";
    System.out.println("Eynidirmi (equals): " + text1.equals(text2));
    System.out.println("Eynidirmi (equalsIgnoreCase): " + text1.equalsIgnoreCase(text2));
    System.out.println("Müqayisə (compareTo): " + text1.compareTo(text2));
  }
}
// Çıxış:
// Eynidirmi (equals): false
// Eynidirmi (equalsIgnoreCase): true
// Müqayisə (compareTo): -32

public class StringFormatting {
  public static void main(String[] args) {
    String name = "Aysel";
    int age = 20;
    String formatted = String.format("Ad: %s, Yaş: %d", name, age);
    System.out.println(formatted);
  }
}
// Çıxış: Ad: Aysel, Yaş: 20

public class ProductDescription {
  public static void main(String[] args) {
    String product = "Telefon";
    double price = 599.99;
    String description = String.format("Məhsul: %s, Qiymət: %.2f AZN", product, price);
    System.out.println(description);
  }
}
// Çıxış: Məhsul: Telefon, Qiymət: 599.99 AZN

