public class StringDefinition {
  public static void main(String[] args) {
    String text = "Привет, мир!";
    System.out.println("Строка: " + text);
  }
}
// Вывод: Строка: Привет, мир!

public class StringImmutability {
  public static void main(String[] args) {
    String text = "Привет";
    text = text + ", мир!"; // Создаётся новая строка
    System.out.println("Результат: " + text);
  }
}
// Вывод: Результат: Привет, мир!

public class StringConcatenation {
  public static void main(String[] args) {
    String first = "Привет";
    String second = "Мир";
    String result = first + ", " + second + "!";
    System.out.println("Объединённая строка: " + result);
    // Использование метода concat
    String concatResult = first.concat(" ").concat(second);
    System.out.println("С помощью concat: " + concatResult);
  }
}
// Вывод:
// Объединённая строка: Привет, Мир!
// С помощью concat: Привет Мир

public class StringMethods {
